"use client";

import { codeToHtml } from "shiki";
import { useEffect, useState } from "react";
import { Button } from "@/components/ui/button";
import { CheckIcon, Copy } from "lucide-react";
import type { BundledLanguage } from "shiki";
import { cn } from "@/lib/utils";

interface CodeBlockProps {
  children: string;
  language?: BundledLanguage;
  filename?: string;
  "aria-label"?: string;
  copyable?: boolean;
  className?: string;
}

export function CodeBlock({
  children,
  language = "tsx",
  filename,
  "aria-label": ariaLabel,
  copyable = false,
  className,
}: CodeBlockProps) {
  const [html, setHtml] = useState<string>("");
  const [isCopied, setIsCopied] = useState(false);

  useEffect(() => {
    async function highlight() {
      const result = await codeToHtml(children, {
        lang: language,
        themes: {
          light: "github-light",
          dark: "github-dark",
        },
        defaultColor: false,
      });

      const tempDiv = document.createElement("div");
      tempDiv.innerHTML = result;

      const preElement = tempDiv.querySelector("pre");
      if (preElement) {
        preElement.classList.add("overflow-x-auto", "p-4", "font-mono");
      }

      setHtml(tempDiv.innerHTML);
    }

    highlight();
  }, [children, language]);

  const handleCopy = () => {
    navigator.clipboard.writeText(children);
    setIsCopied(true);
    setTimeout(() => {
      setIsCopied(false);
    }, 1000);
  };

  return (
    <div
      className={cn(
        "overflow-hidden rounded-md border bg-background",
        className,
      )}
    >
      {filename && (
        <div className="flex items-center justify-between border-b pr-1.5 pl-4 h-10">
          <span className="text-sm text-muted-foreground">{filename}</span>
          {copyable && (
            <Button
              variant="ghost"
              size="icon"
              className="size-7 relative cursor-pointer active:scale-[0.97] transition-all ease-out duration-200 inline-flex items-center justify-center rounded-md text-neutral-900 disabled:pointer-events-none disabled:opacity-100 dark:text-neutral-50"
              onClick={handleCopy}
            >
              {isCopied
                ? <CheckIcon className="size-3.5 text-emerald-500" />
                : <Copy className="size-3.5" />}
            </Button>
          )}
        </div>
      )}
      <div className="relative" aria-label={ariaLabel}>
        <div className="text-sm" dangerouslySetInnerHTML={{ __html: html }} />
        {copyable && !filename && (
          <div className="absolute top-2.5 right-2.5">
            <Button
              variant="outline"
              size="icon"
              className="size-7 border border-border dark:bg-[#191919] dark:hover:bg-[#212121]"
              onClick={handleCopy}
            >
              {isCopied
                ? <CheckIcon className="size-3.5 text-emerald-500" />
                : <Copy className="size-3.5" />}
            </Button>
          </div>
        )}
      </div>
    </div>
  );
}
